class Solution:
    def numberOfSpecialChars(self, word: str) -> int:
        lower_last = [-1] * 26
        upper_first = [float('inf')] * 26

        for idx, ch in enumerate(word):
            if 'a' <= ch <= 'z':
                c = ord(ch) - ord('a')
                if lower_last[c] == -1:
                    lower_last[c] = idx
            else:
                c = ord(ch) - ord('A')
                if upper_first[c] == float('inf'):
                    upper_first[c] = idx

        count = 0
        for i in range(26):
            if lower_last[i] != -1 and upper_first[i] != float('inf') and lower_last[i] < upper_first[i]:
                count += 1
        return count
